export function getContentPrompt(nicheId: string, productTypeId: string, customTitle?: string): string {
  const title = customTitle || productTypeId.replace(/-/g, ' ');
  const specific: Record<string, Record<string, string>> = {
    adhd: {
      'daily-planner': `Create content for an ADHD-friendly daily planner titled "${title}". Return ONLY valid JSON:\n{"title":"${title}","subtitle":"One step at a time — you've got this","date_label":"Date: ___________","top_3_priorities":["Most important task today","Second priority","Third priority"],"time_blocks":[{"time":"7:00 AM","task":""},{"time":"8:00 AM","task":""},{"time":"9:00 AM","task":""},{"time":"10:00 AM","task":""},{"time":"11:00 AM","task":""},{"time":"12:00 PM","task":""},{"time":"1:00 PM","task":""},{"time":"2:00 PM","task":""},{"time":"3:00 PM","task":""},{"time":"4:00 PM","task":""},{"time":"5:00 PM","task":""},{"time":"6:00 PM","task":""}],"win_of_day":"Today's Win: ___________","energy_check":"Energy check (circle one): 🪫 Depleted  😴 Low  😐 Okay  🙂 Good  ⚡ Energized","water_check":"Water (circle glasses drunk): 1  2  3  4  5  6  7  8","affirmation":"You don't have to do it all. You just have to start."}`,
      'brain-dump': `Create content for an ADHD brain dump worksheet. Return ONLY valid JSON:\n{"title":"Brain Dump","subtitle":"Get everything out of your head — no filter, no judgment","instructions":"Set a 10-minute timer. Write down EVERYTHING swirling in your brain. Don't sort or judge — just get it out.","categories":[{"name":"Tasks & To-Dos","icon":"✅","lines":7},{"name":"Worries & Anxieties","icon":"😰","lines":5},{"name":"Ideas & Inspiration","icon":"💡","lines":5},{"name":"People to Contact","icon":"📱","lines":4},{"name":"Random Thoughts","icon":"🌀","lines":5}],"after_dump_prompt":"Now circle ONE thing to act on first. Just one.","affirmation":"Your brain isn't broken — it's just very busy. That's okay."}`,
      'dopamine-menu': `Create a dopamine menu for ADHD. Return ONLY valid JSON:\n{"title":"My Dopamine Menu","subtitle":"Choose based on how much energy you have right now","sections":[{"name":"🍎 Snacks (1-5 min)","description":"Quick dopamine hits","items":["Dance to one song","Step outside for fresh air","Doodle or color freely","Drink a cold glass of water","Text a friend a meme","Stretch or shake out your body","Pet your animal"]},{"name":"🍽️ Meals (5-20 min)","description":"Medium engagement activities","items":["Watch a YouTube video","Tidy one small area","Call or voice-note a friend","Play a quick mobile game","Go for a short walk around the block","Make a cup of tea or coffee","Do 10 minutes of a hobby"]},{"name":"🎂 Feasts (20+ min)","description":"Deep focus activities","items":["Watch an episode of a show","Play video games","Work on a creative project","Cook a new recipe","Read a book or comic","Listen to a podcast while doing something"]},{"name":"🥗 Veggies (responsible boosts)","description":"Productive dopamine sources","items":["Answer 3 emails","Pay one bill","Do one load of laundry","Prep tomorrow's outfit","Review your calendar","Water your plants"]}],"note":"All activities are valid choices. Meet yourself where you are today — no guilt."}`,
      'micro-task': `Create a micro-task breaker worksheet for ADHD. Return ONLY valid JSON:\n{"title":"Micro-Task Breaker","subtitle":"Big tasks feel impossible — break them into tiny steps","instructions":"Write the task that feels overwhelming, then break it into the tiniest possible steps (2-5 minutes each).","categories":[{"name":"The Big Task I Am Avoiding","icon":"😬","lines":2},{"name":"Why It Feels Hard Right Now","icon":"🧠","lines":2},{"name":"Tiny Step 1 (just 2 min)","icon":"1️⃣","lines":2},{"name":"Tiny Step 2","icon":"2️⃣","lines":2},{"name":"Tiny Step 3","icon":"3️⃣","lines":2},{"name":"Tiny Step 4","icon":"4️⃣","lines":2},{"name":"Tiny Step 5","icon":"5️⃣","lines":2},{"name":"My Reward When Done","icon":"🎉","lines":2}],"after_dump_prompt":"Circle the FIRST tiny step. Set a 2-minute timer. Begin.","affirmation":"Starting is the hardest part. Once you begin, momentum builds."}`,
      'habit-streak': `Create a 30-day habit streak tracker for ADHD. Return ONLY valid JSON:\n{"title":"Habit Streak Tracker","subtitle":"30 days — progress not perfection","date_label":"Month: ___________","sections":[{"name":"My Habits to Track","description":"Choose 3-5 habits that matter most to you","items":["Habit 1: ___________________________","Habit 2: ___________________________","Habit 3: ___________________________","Habit 4: ___________________________","Habit 5: ___________________________"]},{"name":"Tracking Grid","description":"Color in each box when you complete that habit","items":["Days 1-10: [ ][ ][ ][ ][ ][ ][ ][ ][ ][ ]","Days 11-20: [ ][ ][ ][ ][ ][ ][ ][ ][ ][ ]","Days 21-30: [ ][ ][ ][ ][ ][ ][ ][ ][ ][ ]"]},{"name":"My Streak Rewards","description":"Celebrate your wins","items":["5-day streak: ___________________________","10-day streak: ___________________________","30-day streak: ___________________________"]}],"affirmation":"Missing a day doesn't break your streak — giving up does. Just keep going."}`,
      'morning-ritual': `Create a morning ritual checklist for ADHD. Return ONLY valid JSON:\n{"title":"Morning Ritual","subtitle":"Set the tone for a good day — one step at a time","date_label":"Date: ___________","sections":[{"name":"Wake Up Basics (0-10 min)","description":"The must-dos first","items":["Drink a glass of water immediately","Open blinds / get some light","Splash face with cold water","Take any morning medications","Quick body stretch (2 min)"]},{"name":"Body Care (10-20 min)","description":"Take care of your physical self","items":["Brush teeth","Wash face","Get dressed (lay out clothes night before)","Eat something — even just a snack","Check today's weather"]},{"name":"Mind Prep (5-10 min)","description":"Set your intentions","items":["Write today's ONE most important task","Check your calendar for today","Spend 2 minutes outside or by a window","Quick breathing exercise"]},{"name":"Optional Add-Ons","description":"Do these when you have extra time","items":["Journal for 5 minutes","Exercise or walk","Make a healthy breakfast","Meditate for 5 minutes"]}],"affirmation":"A consistent morning routine reduces decision fatigue and sets you up to win."}`,
      'focus-timer': `Create a Pomodoro-style focus session log for ADHD. Return ONLY valid JSON:\n{"title":"Focus Timer Log","subtitle":"25 minutes on, 5 minutes off — protect your attention","date_label":"Date: ___________","top_3_priorities":["Session goal #1","Session goal #2","Session goal #3"],"categories":[{"name":"Session 1 — Task","icon":"⏱️","lines":2},{"name":"Session 1 — Notes & Distractions","icon":"📝","lines":2},{"name":"Session 2 — Task","icon":"⏱️","lines":2},{"name":"Session 2 — Notes & Distractions","icon":"📝","lines":2},{"name":"Session 3 — Task","icon":"⏱️","lines":2},{"name":"Session 3 — Notes & Distractions","icon":"📝","lines":2},{"name":"Session 4 — Task","icon":"⏱️","lines":2},{"name":"Session 4 — Notes & Distractions","icon":"📝","lines":2},{"name":"End of Day Reflection","icon":"🌙","lines":3}],"affirmation":"Deep work is a superpower. Even one focused session changes your day."}`,
      'weekly-reset': `Create a weekly reset worksheet for ADHD. Return ONLY valid JSON:\n{"title":"Weekly Reset","subtitle":"Reflect on last week, prepare for the next","date_label":"Week of: ___________","sections":[{"name":"Last Week — Wins","description":"What went well? Even small wins count.","items":["Win #1:","Win #2:","Win #3:"]},{"name":"Last Week — What Drained Me","description":"What took more energy than expected?","items":["Energy drain #1:","Energy drain #2:"]},{"name":"Unfinished Business","description":"What didn't get done? No judgment — just awareness.","items":["Carry forward #1:","Carry forward #2:","Carry forward #3:"]},{"name":"Next Week — Top Priorities","description":"What are the 3 most important things?","items":["Priority #1:","Priority #2:","Priority #3:"]},{"name":"This Week I Will Let Go Of","description":"Release what isn't serving you","items":["I release:","I forgive myself for:"]}],"affirmation":"Every week is a fresh start. You don't carry your mistakes — you carry your lessons."}`,
    },
    mdd: {
      'mood-checkin': `Create a daily mood check-in sheet for MDD support. Return ONLY valid JSON:\n{"title":"Daily Mood Check-In","subtitle":"Checking in is an act of self-care","date_label":"Date:","sections":[{"name":"Overall Mood (circle one)","description":"1 = Very Low  2 = Low  3 = Neutral  4 = Good  5 = Great","items":["😢 1 — Very Low","😔 2 — Low","😐 3 — Neutral","🙂 4 — Good","😊 5 — Great"]},{"name":"I Feel (check all that apply)","description":"There is no wrong answer here","items":["Sad","Anxious","Numb","Hopeful","Grateful","Tired","Irritable","Calm","Lonely","Connected","Overwhelmed","Content","Scared","Safe","Confused","Motivated"]},{"name":"Today's Prompts","description":"Answer as much or as little as you like","items":["One thing that happened today:","One thing I am grateful for, no matter how small:","One thing I did for myself today:","What do I need right now?"]}],"affirmation":"You showed up today. That is enough."}`,
      'gratitude-journal': `Create a gratitude journal page. Return ONLY valid JSON:\n{"title":"Gratitude Journal","subtitle":"Small moments of light matter more than you know","date_label":"Date:","sections":[{"name":"3 Things I Am Grateful For Today","description":"They can be tiny — a warm drink, sunlight, breathing","items":["1.","2.","3."]},{"name":"A Person Who Made My Life Better","description":"Write their name and one reason why","items":["Person:","Why I appreciate them:"]},{"name":"Something My Body Did for Me Today","description":"Even just breathing counts","items":["My body:"]},{"name":"A Challenge That Is Teaching Me Something","description":"Reframe: what is this difficulty showing you?","items":["Challenge:","What it is teaching me:"]},{"name":"A Small Moment of Joy I Noticed","description":"What tiny beautiful thing happened?","items":["Moment of joy:"]}],"affirmation":"Gratitude doesn't erase pain. It reminds you there is also light."}`,
      'small-win-cards': `Create small win celebration cards for MDD support. Return ONLY valid JSON:\n{"title":"Small Win Cards","subtitle":"Every step forward matters — no win is too small","sections":[{"name":"Today I Am Proud That I...","description":"Fill in each card with a win, big or small","items":["Got out of bed","Ate something today","Replied to a message","Took my medication","Drank water","Went outside","Did something creative","Asked for help","Said no to something draining","Kept going even when it was hard","Was kind to myself","Showed up for someone I love"]},{"name":"This Week's Biggest Win","description":"Write your top win from this week","items":["My win:","How it made me feel:","Who I could share this with:"]},{"name":"Evidence That I Am Getting Better","description":"Look back at your progress","items":["One month ago I struggled with:","Now I can:"]}],"affirmation":"Progress is not always visible, but it is real. You are growing, even on the hard days."}`,
      'self-care-menu': `Create a self-care menu for MDD support. Return ONLY valid JSON:\n{"title":"Self-Care Menu","subtitle":"Choose what your body, mind, and soul need right now","sections":[{"name":"⚡ Quick Care (1-5 min)","description":"When you have very little energy","items":["Drink a glass of cold water","Step outside for 2 minutes of fresh air","Look out the window at something natural","Take 5 slow deep breaths","Stretch your arms above your head","Text someone you trust: 'Hey'","Put on a song that makes you feel something"]},{"name":"🌿 Gentle Care (5-20 min)","description":"Low effort, meaningful impact","items":["Wash your face with warm water","Make a hot drink and sip slowly","Lie down with a blanket and rest","Watch something comforting","Journal one sentence about how you feel","Take a 10-minute walk","Light a candle or open a window"]},{"name":"🌸 Nourishing Care (20+ min)","description":"When you have more capacity","items":["Take a long shower or bath","Cook a meal you enjoy","Spend time with a pet or plant","Watch a favorite comfort show","Call someone who makes you feel safe","Go for a nature walk","Create something — draw, write, make"]},{"name":"🤝 Connection Care","description":"You do not have to do this alone","items":["Reach out to one person today","Tell someone how you really are","Schedule something to look forward to","Join an online support community","Talk to your therapist or counselor"]}],"affirmation":"Self-care is not a luxury. It is how you stay alive and keep going."}`,
      'therapy-prep': `Create a therapy preparation sheet for MDD. Return ONLY valid JSON:\n{"title":"Therapy Prep Sheet","subtitle":"Come prepared — get the most from your session","date_label":"Session Date:","sections":[{"name":"Since Our Last Session...","description":"What has happened in your life?","items":["Something I want to tell my therapist:","A situation that triggered strong emotions:","A win or moment I felt proud of:","Something I tried differently:"]},{"name":"How I Have Been Feeling","description":"Rate 1 (very hard) to 10 (doing well)","items":["Overall mood this week (1-10):","Anxiety level (1-10):","Sleep quality (1-10):","Energy level (1-10):"]},{"name":"What I Want to Focus On Today","description":"Be specific — what do you most need from this session?","items":["Main topic:","What outcome would feel helpful?","A question I want to ask:"]},{"name":"After the Session","description":"Fill in after your appointment","items":["Key insight from today:","One thing I will try this week:","How I felt leaving the session:"]}],"affirmation":"Asking for help is one of the bravest things you can do."}`,
      'affirmation-deck': `Create printable affirmation cards for MDD support. Return ONLY valid JSON:\n{"title":"Affirmation Cards","subtitle":"Cut out and keep one wherever you need a reminder","sections":[{"name":"For Hard Mornings","description":"When getting up feels impossible","items":["I am allowed to take it one moment at a time.","I have survived every difficult day so far. 100%.","Today does not have to be perfect to be worthwhile.","My worth is not measured by my productivity.","It is okay to need rest."]},{"name":"For Anxious Moments","description":"When your mind races","items":["This feeling is temporary. It will pass.","I am safe in this moment.","I can slow down and breathe.","I do not have to solve everything right now.","I choose to release what I cannot control."]},{"name":"For Tough Days","description":"When nothing feels right","items":["I am more than my diagnosis.","Healing is not linear — and that is okay.","I deserve kindness, especially from myself.","Small steps still move me forward.","I am not a burden. I am a person who is struggling, and that is human."]},{"name":"For Reminders of Your Strength","description":"Read these when you forget","items":["I have been through hard things before, and I am still here.","I am doing the best I can with what I have right now.","Someone in my life is glad I exist.","I am worthy of love and belonging.","My story is still being written."]}],"affirmation":"Print these, cut them out, put one in your wallet, on your mirror, or under your pillow."}`,
      'progress-tracker': `Create a recovery progress tracker for MDD support. Return ONLY valid JSON:\n{"title":"Progress Tracker","subtitle":"Healing happens slowly, then all at once","date_label":"Tracking Period:","sections":[{"name":"Where I Started","description":"Documenting where you began is powerful","items":["How I was feeling when I started:","What was the hardest part:","What I was hoping would change:"]},{"name":"Weekly Check-Ins","description":"Rate each area 1 (very difficult) to 5 (doing well)","items":["Week 1 — Mood: _/5  Energy: _/5  Sleep: _/5  Connections: _/5","Week 2 — Mood: _/5  Energy: _/5  Sleep: _/5  Connections: _/5","Week 3 — Mood: _/5  Energy: _/5  Sleep: _/5  Connections: _/5","Week 4 — Mood: _/5  Energy: _/5  Sleep: _/5  Connections: _/5"]},{"name":"Evidence of Growth","description":"Capture proof that you are changing","items":["Something I can do now that I couldn't before:","A thought pattern that has shifted:","A relationship that has improved:","A coping skill I have used successfully:"]},{"name":"What Has Helped Most","description":"Your personal toolkit","items":["Therapy insight that changed things:","Self-care practice that works:","Person who has supported me:","Medication or supplement change:"]}],"affirmation":"You are not the same person you were when you started. That is the whole point."}`,
      'gentle-planner': `Create a gentle daily planner for MDD support. Return ONLY valid JSON:\n{"title":"Gentle Daily Planner","subtitle":"Low pressure, high compassion","date_label":"Date:","sections":[{"name":"How I Am Waking Up Today","description":"No judgment — just honest awareness","items":["My mood this morning (circle): 😢 😔 😐 🙂 😊","Energy level (circle): Empty  Low  Okay  Good  High","One word to describe how I feel:"]},{"name":"Today's Gentle Intentions","description":"Not a to-do list — just kind intentions","items":["One thing I'd like to do for my body:","One thing I'd like to do for my mind:","One tiny thing I'd like to accomplish:","Permission I give myself today:"]},{"name":"Scheduled Things","description":"Just the essentials","items":["Morning:","Afternoon:","Evening:","Medication / appointments:"]},{"name":"Evening Reflection","description":"End the day with kindness","items":["One thing that happened today:","One thing I did well:","How I feel right now:","What I need tonight:"]}],"affirmation":"You are allowed to have a gentle day. You do not always have to push through."}`,
    },
    anxiety: {
      'grounding-5-4-3-2-1': `Create a 5-4-3-2-1 grounding exercise card. Return ONLY valid JSON:\n{"title":"5-4-3-2-1 Grounding","subtitle":"Return to the present moment — right here, right now","steps":[{"number":5,"sense":"SEE","icon":"👁️","instruction":"Name 5 things you can see right now. Look around slowly."},{"number":4,"sense":"TOUCH","icon":"✋","instruction":"Name 4 things you can physically feel. Your feet on the floor, your clothes on your skin."},{"number":3,"sense":"HEAR","icon":"👂","instruction":"Name 3 things you can hear. Near sounds, far sounds, quiet sounds."},{"number":2,"sense":"SMELL","icon":"👃","instruction":"Name 2 things you can smell. If nothing, try sniffing your sleeve or something nearby."},{"number":1,"sense":"TASTE","icon":"👅","instruction":"Name 1 thing you can taste right now."}],"after_instruction":"Take 3 slow, deep breaths. In for 4 counts, hold for 2, out for 6. You are safe. You are here.","reminder":"This exercise works because it interrupts the anxiety loop and forces your brain into the present. The more you practice, the faster it works."}`,
      'cbt-thought-record': `Create a CBT thought record worksheet. Return ONLY valid JSON:\n{"title":"CBT Thought Record","subtitle":"Challenge anxious thoughts with evidence — not emotion","columns":[{"name":"Situation","prompt":"What happened? Where were you? Who was there?"},{"name":"Automatic Thought","prompt":"What went through your mind immediately? What did you tell yourself?"},{"name":"Emotions","prompt":"What emotions did you feel? Rate intensity 0-100"},{"name":"Evidence FOR","prompt":"What facts support this thought being true?"},{"name":"Evidence AGAINST","prompt":"What facts do NOT support this thought?"},{"name":"Balanced Thought","prompt":"What is a more realistic, balanced way to see this?"},{"name":"Outcome","prompt":"How do you feel now? Rate the original emotion 0-100 again"}],"cognitive_distortions":["All-or-nothing thinking","Catastrophizing (worst case)","Mind reading (assuming what others think)","Fortune telling (predicting the future)","Overgeneralization","Emotional reasoning (feeling = fact)","Should/must statements","Personalization (taking blame)","Mental filter (focusing only on negatives)","Discounting the positive"],"reminder":"Your thoughts are not facts. They are mental events that can be questioned, tested, and changed."}`,
      'box-breathing': `Create a box breathing guide. Return ONLY valid JSON:\n{"title":"Box Breathing","subtitle":"Activate your parasympathetic nervous system in 2 minutes","steps":[{"number":1,"sense":"INHALE","icon":"⬆️","instruction":"Breathe IN slowly and deeply through your nose for 4 counts: 1... 2... 3... 4..."},{"number":2,"sense":"HOLD","icon":"➡️","instruction":"HOLD your breath (lungs full) for 4 counts: 1... 2... 3... 4..."},{"number":3,"sense":"EXHALE","icon":"⬇️","instruction":"Breathe OUT slowly through your mouth for 4 counts: 1... 2... 3... 4..."},{"number":4,"sense":"HOLD","icon":"⬅️","instruction":"HOLD your breath (lungs empty) for 4 counts: 1... 2... 3... 4... Then begin again."}],"after_instruction":"Repeat 4-8 times. This technique is used by Navy SEALs, surgeons, and therapists to reduce acute stress and anxiety. It is scientifically validated.","reminder":"If 4 counts feels too short, try 5 or 6. If it feels too long, try 3. Find what works for your body."}`,
      'worry-dump': `Create a worry dump journal for anxiety. Return ONLY valid JSON:\n{"title":"Worry Dump Journal","subtitle":"Get the worries out of your head and onto the page","sections":[{"name":"Brain Dump — All My Worries","description":"Write every worry without filtering. Don't judge them — just get them out.","items":["Worry 1:","Worry 2:","Worry 3:","Worry 4:","Worry 5:","Worry 6:"]},{"name":"Reality Check","description":"For each worry, ask these questions","items":["Is this worry based on a fact or a feeling?","What is the REALISTIC worst case? (Not the catastrophic one)","What is the REALISTIC best case?","What is most LIKELY to happen?","If the worst happened, could I cope? How?"]},{"name":"What I Can Control","description":"Separate controllable from uncontrollable","items":["Things I CAN control or influence:","Things I CANNOT control (let these go):"]},{"name":"Action Plan","description":"For worries with actionable steps","items":["One thing I can do TODAY about this:","One thing I can do THIS WEEK:"]}],"affirmation":"Anxiety lives in the future. You are here, now, and you can handle the present moment."}`,
      'safety-plan': `Create a personal safety plan for crisis moments. Return ONLY valid JSON:\n{"title":"My Personal Safety Plan","subtitle":"For when things feel overwhelming — a plan you made for yourself","sections":[{"name":"Step 1 — Warning Signs","description":"Signs that tell me I'm struggling","items":["Physical signs (e.g., racing heart, can't sleep):","Emotional signs (e.g., feeling hopeless, isolated):","Behavioral signs (e.g., withdrawing, not eating):"]},{"name":"Step 2 — My Coping Strategies","description":"Things I can do on my own to feel better","items":["Distraction that works for me:","Calming activity I can do alone:","A safe place I can go to:","A physical activity that helps:"]},{"name":"Step 3 — People Who Help","description":"Safe people I can reach out to","items":["Person 1: Name _________ Phone _________","Person 2: Name _________ Phone _________","Person 3: Name _________ Phone _________"]},{"name":"Step 4 — Professional Support","description":"Professional help I can contact","items":["My therapist: _________________________","My doctor: _________________________","Crisis line: 988 (call or text)","Emergency: 911 or nearest ER"]},{"name":"Step 5 — Making My Environment Safer","description":"Steps to reduce risk during a crisis","items":["Things I can remove or lock away:","Person who can hold items for me:","Place I can go that feels safe:"]},{"name":"Step 6 — Reasons to Stay Safe","description":"My reasons — personal to me","items":["People who need me:","Things I want to experience:","Values that matter to me:"]}}],"affirmation":"You made this plan because you matter. Please follow it. You deserve to be safe."}`,
      'calm-down-kit': `Create a calm-down kit printable for anxiety. Return ONLY valid JSON:\n{"title":"Calm Down Kit","subtitle":"Your personalized toolkit for anxious moments","sections":[{"name":"🌬️ Breathing Techniques","description":"Start here — breathing is the fastest regulator","items":["Box Breathing: In 4 → Hold 4 → Out 4 → Hold 4","4-7-8 Breathing: In 4 → Hold 7 → Out 8","Deep belly breathing: hand on stomach, feel it rise","Alternate nostril breathing: cover one nostril at a time","Lion's breath: inhale deeply, exhale through open mouth with tongue out"]},{"name":"🧠 Grounding Techniques","description":"Return to the present moment","items":["5-4-3-2-1 Senses (see, touch, hear, smell, taste)","Name 10 things you can see right now","Say today's date and where you are out loud","Press your feet firmly into the floor","Hold an ice cube and focus on the sensation"]},{"name":"🤸 Body-Based Techniques","description":"Move the anxiety through your body","items":["Progressive muscle relaxation (tense and release each muscle group)","Shake your body for 30 seconds like you just finished a race","Cold water on your face or wrists","A brisk 5-minute walk","Jumping jacks or burpees to burn off adrenaline"]},{"name":"🎯 Cognitive Techniques","description":"Challenge the anxious thinking","items":["Write down the worst case — then the realistic case","Ask: Is this fact or feeling?","Say the worry out loud — it often sounds smaller","'I am having the thought that...' (create distance from thoughts)","Ask: Will this matter in 5 years?"]},{"name":"🌿 Soothing Techniques","description":"Calm your nervous system","items":["Make a cup of tea or warm drink","Wrap in a blanket or weighted blanket","Listen to calming music or nature sounds","Aromatherapy: lavender, chamomile","Pet an animal"]}],"affirmation":"Having this kit means you planned ahead. That is wisdom. Use it without shame."}`,
      'what-i-can-control': `Create a control circle worksheet for anxiety. Return ONLY valid JSON:\n{"title":"Control Circle","subtitle":"Focus your energy where it actually makes a difference","sections":[{"name":"Inside My Circle — What I CAN Control","description":"Write down things you have real influence over","items":["My responses and reactions","My words and tone","How much effort I put in","My daily habits and routines","Who I spend time with","How I take care of my body","What I choose to focus on","How I ask for help"]},{"name":"Outside My Circle — What I CANNOT Control","description":"Write down things you've been trying to control but can't","items":["Other people's opinions","Other people's choices and behavior","The past","The future","The economy or world events","What others say about me","Other people's emotions","Traffic, weather, random events"]},{"name":"My Worries — Which Circle?","description":"Sort your current worries","items":["Worry 1 → Inside/Outside circle?","Worry 2 → Inside/Outside circle?","Worry 3 → Inside/Outside circle?","Worry 4 → Inside/Outside circle?"]},{"name":"Action Plan","description":"For things inside your circle","items":["One thing inside my circle I will act on:","One thing outside my circle I will practice releasing:"]}],"affirmation":"You are not powerless. You have enormous influence over your inner world — and that is where real peace lives."}`,
      'anxiety-tracker': `Create an anxiety tracker for monitoring triggers and coping. Return ONLY valid JSON:\n{"title":"Anxiety Tracker","subtitle":"Patterns become visible when you track them","date_label":"Date:","categories":[{"name":"Anxiety Level (1-10)","icon":"📊","lines":1},{"name":"What Triggered It","icon":"⚡","lines":2},{"name":"Physical Symptoms","icon":"🫀","lines":2},{"name":"Thoughts I Had","icon":"💭","lines":3},{"name":"Coping Tool Used","icon":"🧰","lines":2},{"name":"How It Resolved","icon":"✅","lines":2},{"name":"What I Would Do Differently","icon":"🔄","lines":2}],"affirmation":"Tracking your anxiety gives you power over it. You are the expert on your own patterns."}`,
    },
    social: {
      'conversation-starters': `Create conversation starter cards for social anxiety and social skills. Return ONLY valid JSON:\n{"title":"Conversation Starters","subtitle":"Never be stuck for something to say again","sections":[{"name":"🌱 Light & Easy — New People","description":"Safe, low-stakes openers","items":["What's the best meal you've had recently?","Are you working on anything exciting lately?","What do you do to unwind after a long day?","Any good shows, books, or podcasts you'd recommend?","What's your go-to weekend activity?","How long have you lived in this area?","What do you do for work — do you enjoy it?"]},{"name":"🔥 Deeper Connection — Building Trust","description":"For people you want to know better","items":["What's something you've changed your mind about recently?","What's the best advice you've ever received?","What skill do you most want to learn this year?","What are you most proud of in your life right now?","What does your ideal life look like in 5 years?","What's something most people don't know about you?"]},{"name":"😄 Fun & Playful — Lightening the Mood","description":"To add some joy and laughter","items":["What superpower would you choose and why?","Pineapple on pizza — yes or no? Defend your answer.","What's your most unpopular opinion?","Best trip or vacation you've ever taken?","What would your ideal Saturday look like?","If you could only eat one meal forever, what would it be?"]},{"name":"🤝 Reconnecting — People You Already Know","description":"For when you haven't spoken in a while","items":["What's been the highlight of your year so far?","What are you excited about right now?","How have things changed for you lately?","What are you focusing on these days?"]}],"reminder":"The secret to good conversation: ask, listen genuinely, then share. Curiosity beats performance every time."}`,
      'social-battery': `Create a social battery tracker for introversion and social recovery. Return ONLY valid JSON:\n{"title":"Social Battery Tracker","subtitle":"Monitor your energy around people — it's real and it matters","sections":[{"name":"My Battery Level Right Now","description":"Check in with yourself honestly","items":["100% — Fully charged, ready to engage","75% — Good, can handle most social things","50% — Okay, selective about interactions","25% — Running low, need quiet soon","0% — Depleted, need alone time urgently"]},{"name":"Things That DRAIN My Battery","description":"Everyone is different — what drains yours?","items":["Large groups or parties","Small talk with strangers","Conflict or difficult conversations","Being 'on' for too long without a break","Noisy, crowded environments","Performing or presenting","Phone calls (for some people)"]},{"name":"Things That RECHARGE My Battery","description":"What restores your energy?","items":["Alone time with no obligations","Quiet activities (reading, creating, walking)","One-on-one time with close friends","Familiar routines and environments","Physical exercise","Time in nature","Creative projects"]},{"name":"This Week's Social Log","description":"Track when you socialized and how it felt","items":["Monday — Event: ___ Battery before: ___ Battery after: ___","Wednesday — Event: ___ Battery before: ___ Battery after: ___","Friday — Event: ___ Battery before: ___ Battery after: ___"]},{"name":"Recovery Plan","description":"What I need after a draining social event","items":["Immediately after (0-1 hour):","Later that evening:","The next morning:"]}],"affirmation":"Introversion and social anxiety are not flaws. Knowing your limits and honoring them is self-awareness, not weakness."}`,
      'boundary-scripts': `Create boundary setting scripts for social situations. Return ONLY valid JSON:\n{"title":"Boundary Scripts","subtitle":"Pre-written words for setting limits with confidence","sections":[{"name":"Declining Invitations","description":"How to say no without over-explaining","items":["'I won't be able to make it, but thank you for thinking of me.'","'That doesn't work for me, but I hope you have a great time.'","'I'm going to sit this one out — maybe next time.'","'I have something else going on that day.' (you don't owe details)","'I need some downtime this weekend, but let's plan something soon.'"]},{"name":"Setting Limits at Work","description":"Professional boundary language","items":["'I'm at capacity right now — can we revisit this next week?'","'I want to do this well, so I need to finish what I'm working on first.'","'I'm not the right person for that, but [person] might be able to help.'","'I can take that on if we deprioritize [other task].'","'I need until [date] to give this the attention it deserves.'"]},{"name":"With Family or Close Friends","description":"For closer relationships that need limits","items":["'I love you and I need some space right now.'","'That topic is something I'm not able to discuss right now.'","'I need you to stop [specific behavior]. It's not okay with me.'","'I can't keep helping with this without it affecting my own wellbeing.'","'I want to support you, and I also need to take care of myself.'"]},{"name":"Stopping Boundary Violations","description":"When someone pushes past your limits","items":["'I've already said no, and that's my final answer.'","'I need you to respect what I just said.'","'That's not something I'm willing to negotiate.'","'If this continues, I'm going to need to [consequence].'"]}],"affirmation":"A boundary is not a wall — it's a statement of what you need to feel safe and respected. You are allowed to have them."}`,
      'post-social-recovery': `Create a post-social recovery plan. Return ONLY valid JSON:\n{"title":"Post-Social Recovery","subtitle":"Recharge your battery after social events","sections":[{"name":"How Did It Go? (Debrief)","description":"Quick honest check-in — no ruminating allowed, just facts","items":["What happened:","Battery before the event (1-10):","Battery after (1-10):","What went well:","What felt hard:","One thing I am proud of (showing up counts!):"]},{"name":"Immediate Recovery (0-1 hour)","description":"Decompress right away","items":["Change into comfortable clothes","Drink water or make a hot drink","Sit or lie in a quiet space","Avoid screens for 10 minutes if possible","Let yourself just breathe and be"]},{"name":"This Evening's Recovery Plan","description":"Protect your evening","items":["Low-energy activity I will do:","Food I want to eat:","When I will go to bed:","Anything I need to process (journal, talk, rest):"]},{"name":"Tomorrow","description":"Give yourself space to recover fully","items":["Plans I can simplify or cancel tomorrow:","Morning priority:","Something kind I will do for myself:"]}],"affirmation":"Social events take real energy. Recovery isn't laziness — it's how introverts and anxious people stay healthy and regulated."}`,
      'email-templates': `Create email templates for difficult social situations. Return ONLY valid JSON:\n{"title":"Email Templates","subtitle":"Copy, paste, adjust, and send — done","sections":[{"name":"Declining a Request","description":"For when you need to say no to work or personal asks","items":["Subject: Re: [Request]","'Hi [Name], Thank you for thinking of me. Unfortunately, I won't be able to [do this] right now due to current commitments. I hope it goes well — [Name]'"]},{"name":"Setting a Work Deadline","description":"Managing expectations professionally","items":["'Hi [Name], I want to make sure I do this properly. I can have [task] ready by [date]. Please let me know if this works. — [Name]'"]},{"name":"Following Up (When No Response)","description":"Polite check-in without being pushy","items":["'Hi [Name], Just following up on my message from [date]. No worries if you've been busy — let me know when you have a moment. — [Name]'"]},{"name":"Canceling Plans","description":"Honest, kind, and brief","items":["'Hi [Name], I'm so sorry to do this, but I need to cancel [plan]. I wasn't feeling up to it and didn't want to show up less than my best. Can we reschedule? — [Name]'"]},{"name":"Addressing a Conflict","description":"When something needs to be said","items":["'Hi [Name], I've been wanting to address something that's been on my mind. [Situation] made me feel [emotion]. I wanted to talk it through because I value [our relationship/working together]. Can we find a time to chat? — [Name]'"]}}],"affirmation":"Hard conversations don't have to be perfect — they just have to happen. Done is better than perfect."}`,
      'meeting-prep': `Create a meeting preparation template. Return ONLY valid JSON:\n{"title":"Meeting Prep","subtitle":"Walk in prepared — walk out with clarity","date_label":"Meeting Date:","categories":[{"name":"Meeting Details","icon":"📅","lines":2},{"name":"My Goal for This Meeting","icon":"🎯","lines":2},{"name":"Key Points I Want to Make","icon":"📌","lines":4},{"name":"Questions I Want to Ask","icon":"❓","lines":4},{"name":"Background Info to Review","icon":"📚","lines":3},{"name":"Potential Challenges","icon":"⚠️","lines":2},{"name":"After Meeting — Action Items","icon":"✅","lines":4}],"affirmation":"Preparation is the antidote to social anxiety in professional settings. You deserve to show up confident."}`,
      'small-talk': `Create a small talk guide for social anxiety. Return ONLY valid JSON:\n{"title":"Small Talk Guide","subtitle":"Small talk is a skill, and skills can be learned","sections":[{"name":"The FORD Method","description":"Safe, universal conversation topics","items":["F — Family: Ask about family (kids, siblings, where they're from)","O — Occupation: What do they do? Do they enjoy it?","R — Recreation: Hobbies, weekend plans, sports","D — Dreams: Goals, places they want to travel, bucket list"]},{"name":"Safe Opening Lines","description":"For any situation","items":["'How do you know [host/organizer]?'","'Have you been to one of these before?'","'What do you think of [event/venue]?'","'What brought you here today?'","'Is this your first time in [city/area]?'"]},{"name":"Conversation Rescuers","description":"When there's a lull or awkward silence","items":["'What's been the highlight of your week?'","'So what do you do when you're not [at this event]?'","'Any recommendations for [restaurants/shows/things to do around here]?'","'I have to admit — I'm better at deep conversations than small talk. What's something you're really into right now?'"]},{"name":"Graceful Exits","description":"How to leave a conversation without awkwardness","items":["'It was really great talking to you — I need to catch [person] before they leave.'","'I'm going to grab a drink — can I get you anything?'","'I should mingle a bit, but I hope to chat more later.'","'It was great meeting you — enjoy the rest of the event.'"]}],"affirmation":"The goal of small talk isn't to be impressive — it's to make the other person feel comfortable. That's it."}`,
      'social-goals': `Create a social goals worksheet for building social skills. Return ONLY valid JSON:\n{"title":"Social Goals","subtitle":"Build the social life you actually want — one small step at a time","sections":[{"name":"My Current Social Situation","description":"Honest reflection — no judgment","items":["What my social life looks like now:","What feels hard or scary:","What I wish were different:","What I am already doing well:"]},{"name":"My Social Goals (3 months)","description":"Be specific and achievable","items":["Goal 1: ___________________________","Goal 2: ___________________________","Goal 3: ___________________________"]},{"name":"Baby Steps to Each Goal","description":"The tiniest possible first step","items":["Step toward Goal 1 (do this week):","Step toward Goal 2 (do this week):","Step toward Goal 3 (do this week):"]},{"name":"Tracking My Progress","description":"Check in weekly","items":["Week 1 — What I tried:","Week 2 — What I tried:","Week 3 — What I tried:","Week 4 — What changed:"]},{"name":"What I Am Proud Of","description":"Celebrate your social courage","items":["A moment I was brave:","A connection I made:","A skill I practiced:"]}],"affirmation":"Social skills are not innate gifts — they are learned through practice. Every attempt, even the awkward ones, counts."}`,
    },
    human: {
      'weekly-planner': `Create a weekly planner. Return ONLY valid JSON:\n{"title":"Weekly Planner","subtitle":"Plan your week with intention and flexibility","date_label":"Week of:","top_3_priorities":["Most important thing this week","Second priority","Third priority"],"time_blocks":[{"time":"Monday","task":""},{"time":"Tuesday","task":""},{"time":"Wednesday","task":""},{"time":"Thursday","task":""},{"time":"Friday","task":""},{"time":"Saturday","task":""},{"time":"Sunday","task":""}],"categories":[{"name":"This Week's Appointments","icon":"📅","lines":4},{"name":"Errands & Tasks","icon":"📋","lines":5},{"name":"Self-Care & Personal","icon":"🌿","lines":3}],"win_of_day":"Weekly Win:","affirmation":"Progress over perfection. Every small step counts."}`,
      'monthly-planner': `Create a monthly planner. Return ONLY valid JSON:\n{"title":"Monthly Planner","subtitle":"See your whole month — stay ahead of it","date_label":"Month:","top_3_priorities":["Top goal this month","Second goal","Third goal"],"categories":[{"name":"Week 1 Focus","icon":"1️⃣","lines":3},{"name":"Week 2 Focus","icon":"2️⃣","lines":3},{"name":"Week 3 Focus","icon":"3️⃣","lines":3},{"name":"Week 4 Focus","icon":"4️⃣","lines":3},{"name":"Important Dates & Deadlines","icon":"📅","lines":5},{"name":"Bills & Financial Dates","icon":"💰","lines":4},{"name":"Personal Goals","icon":"🎯","lines":3},{"name":"Things to Look Forward To","icon":"⭐","lines":3}],"affirmation":"A month well planned is a month well lived."}`,
      'budget-tracker': `Create a monthly budget tracker. Return ONLY valid JSON:\n{"title":"Monthly Budget Tracker","subtitle":"Know where every dollar goes — no surprises","date_label":"Month:","top_3_priorities":["Monthly income goal","Savings goal","Debt payment goal"],"categories":[{"name":"Income Sources","icon":"💵","lines":4},{"name":"Housing (Rent/Mortgage, Utilities)","icon":"🏠","lines":4},{"name":"Food & Groceries","icon":"🛒","lines":4},{"name":"Transportation (Car, Gas, Transit)","icon":"🚗","lines":3},{"name":"Health (Insurance, Medications, Gym)","icon":"💊","lines":3},{"name":"Entertainment & Subscriptions","icon":"🎬","lines":4},{"name":"Personal & Shopping","icon":"🛍️","lines":3},{"name":"Savings & Investments","icon":"🏦","lines":3},{"name":"Debt Payments","icon":"📉","lines":3},{"name":"Miscellaneous","icon":"📦","lines":3}],"affirmation":"Awareness is the first step to financial freedom. You are taking it."}`,
      'meal-planner': `Create a weekly meal planner with grocery list. Return ONLY valid JSON:\n{"title":"Meal Planner","subtitle":"Eat well, stress less about food decisions","date_label":"Week of:","categories":[{"name":"Monday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Tuesday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Wednesday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Thursday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Friday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Saturday — Breakfast / Lunch / Dinner","icon":"🍽️","lines":3},{"name":"Sunday — Prep & Batch Cooking","icon":"👨‍🍳","lines":3},{"name":"Grocery List — Produce","icon":"🥦","lines":5},{"name":"Grocery List — Proteins","icon":"🥩","lines":4},{"name":"Grocery List — Pantry & Other","icon":"🫙","lines":5}],"affirmation":"Meal planning saves time, money, and mental energy. Future you will be grateful."}`,
      'goal-setting': `Create a SMART goal setting worksheet. Return ONLY valid JSON:\n{"title":"Goal Setting","subtitle":"Turn vague wishes into concrete plans","sections":[{"name":"My Goal (The Dream)","description":"What do you want to achieve? Write it as a sentence.","items":["My goal:","Why this goal matters to me:","How achieving this will change my life:"]},{"name":"Make It SMART","description":"Specific, Measurable, Achievable, Relevant, Time-bound","items":["Specific — exactly what will I do?","Measurable — how will I know I succeeded?","Achievable — is this realistic for me right now?","Relevant — why does this matter in my life?","Time-bound — when will I achieve this by?"]},{"name":"Break It Down","description":"Work backwards from the deadline","items":["Step 1 (this week):","Step 2 (this month):","Step 3 (in 3 months):","Step 4 (the final push):"]},{"name":"Potential Obstacles","description":"Anticipate challenges before they happen","items":["Obstacle 1:","How I'll handle it:","Obstacle 2:","How I'll handle it:"]},{"name":"Support & Resources","description":"What and who will help you succeed","items":["Person who will support me:","Resource or tool I need:","Habit I need to build:","Habit I need to break:"]}],"affirmation":"A goal without a plan is just a wish. Now you have a plan."}`,
      'cleaning-schedule': `Create a cleaning schedule printable. Return ONLY valid JSON:\n{"title":"Cleaning Schedule","subtitle":"A clean space, a clear mind — one task at a time","sections":[{"name":"Daily Tasks (10-15 min)","description":"The non-negotiable basics","items":["Dishes / load dishwasher","Wipe kitchen counters","Quick tidy of main living areas","Make bed","Empty trash if full","Quick bathroom wipe-down"]},{"name":"Weekly Tasks (by day)","description":"Spread the work across the week","items":["Monday — Vacuum all floors","Tuesday — Mop hard floors","Wednesday — Clean bathrooms (toilet, sink, shower)","Thursday — Dust surfaces, fans, shelves","Friday — Clean kitchen (stove, inside microwave, fridge wipe)","Saturday — Laundry (wash, dry, fold, put away)","Sunday — Outdoor areas, meal prep, weekly reset"]},{"name":"Monthly Tasks","description":"Deeper cleaning — once a month","items":["Clean inside oven","Wash windows","Wipe baseboards","Clean inside refrigerator","Wash bedding and pillows","Declutter one room or area","Clean light fixtures"]},{"name":"Seasonal Tasks (every 3-6 months)","description":"The big jobs","items":["Deep clean carpets or rugs","Wash curtains and blinds","Clean gutters or outdoor areas","Rotate and clean under furniture","Declutter closets and donate"]}}],"affirmation":"A tidy space isn't about perfection — it's about creating a home that feels like a place to rest."}`,
      'reading-tracker': `Create a reading tracker. Return ONLY valid JSON:\n{"title":"Reading Tracker","subtitle":"Track your reading journey — every book leaves its mark","sections":[{"name":"Currently Reading","description":"What are you reading right now?","items":["Title:","Author:","Genre:","Started:","Goal finish date:","Current page / Total pages:","Rating so far (1-5 stars):"]},{"name":"My Reading Log","description":"Record each book you finish","items":["Book 1: Title __________ Author __________ Rating ⭐⭐⭐⭐⭐ Finished: __","Book 2: Title __________ Author __________ Rating ⭐⭐⭐⭐⭐ Finished: __","Book 3: Title __________ Author __________ Rating ⭐⭐⭐⭐⭐ Finished: __","Book 4: Title __________ Author __________ Rating ⭐⭐⭐⭐⭐ Finished: __","Book 5: Title __________ Author __________ Rating ⭐⭐⭐⭐⭐ Finished: __"]},{"name":"My Reading List — Want to Read","description":"Books you've heard about and want to get to","items":["1.","2.","3.","4.","5.","6.","7.","8."]},{"name":"Year in Books — Stats","description":"Track your reading year","items":["Goal: ___ books this year","Read so far: ___","Favorite genre: ___","Best book I read this year:","Book I'd most recommend:"]}}],"affirmation":"Every book you read makes you a more informed, empathetic, and interesting person."}`,
      'fitness-tracker': `Create a fitness and workout tracker. Return ONLY valid JSON:\n{"title":"Fitness Tracker","subtitle":"Show up, do the work, track the progress","date_label":"Month:","top_3_priorities":["Fitness goal #1","Fitness goal #2","Fitness goal #3"],"categories":[{"name":"Monday — Workout","icon":"💪","lines":3},{"name":"Tuesday — Workout","icon":"💪","lines":3},{"name":"Wednesday — Workout","icon":"💪","lines":3},{"name":"Thursday — Workout","icon":"💪","lines":3},{"name":"Friday — Workout","icon":"💪","lines":3},{"name":"Saturday — Active Recovery","icon":"🧘","lines":2},{"name":"Sunday — Rest & Reflect","icon":"😴","lines":2},{"name":"Weekly Stats","icon":"📊","lines":3},{"name":"Monthly Progress Notes","icon":"📈","lines":4}],"affirmation":"You do not have to be great to start, but you have to start to be great."}`,
      'habit-tracker': `Create a monthly habit tracker. Return ONLY valid JSON:\n{"title":"Habit Tracker","subtitle":"Track any habit for 30 days — consistency creates results","date_label":"Month:","sections":[{"name":"My Habits","description":"Choose 5-8 habits you want to build or maintain","items":["Habit 1: ___________________________","Habit 2: ___________________________","Habit 3: ___________________________","Habit 4: ___________________________","Habit 5: ___________________________","Habit 6: ___________________________"]},{"name":"Tracking Grid — Week 1 (Days 1-7)","description":"Color in each box when you complete that habit","items":["Habit 1: [ ][ ][ ][ ][ ][ ][ ]","Habit 2: [ ][ ][ ][ ][ ][ ][ ]","Habit 3: [ ][ ][ ][ ][ ][ ][ ]","Habit 4: [ ][ ][ ][ ][ ][ ][ ]","Habit 5: [ ][ ][ ][ ][ ][ ][ ]","Habit 6: [ ][ ][ ][ ][ ][ ][ ]"]},{"name":"Tracking Grid — Week 2 (Days 8-14)","description":"Keep going!","items":["Habit 1: [ ][ ][ ][ ][ ][ ][ ]","Habit 2: [ ][ ][ ][ ][ ][ ][ ]","Habit 3: [ ][ ][ ][ ][ ][ ][ ]","Habit 4: [ ][ ][ ][ ][ ][ ][ ]"]},{"name":"Monthly Reflection","description":"End of month check-in","items":["Habit I'm most proud of sticking to:","Habit that needs a different approach:","What helped me stay consistent:","What I'll adjust next month:"]}],"affirmation":"You don't rise to your goals — you fall to your systems. Build the system."}`,
      'vision-board': `Create a guided vision board template. Return ONLY valid JSON:\n{"title":"Vision Board","subtitle":"Visualize the life you are building — make it real on paper","sections":[{"name":"My Life in 1 Year","description":"What does your life look like one year from now?","items":["Where I live:","What my work/career looks like:","How I feel every day:","What my relationships look like:","What I have achieved:"]},{"name":"My Life in 5 Years","description":"Zoom out — the bigger picture","items":["Who I have become:","What I have built or created:","Where I have traveled:","How I spend my time:","Financial picture:"]},{"name":"My Values — What Matters Most","description":"Your vision should be built on your values","items":["Value 1:","Value 2:","Value 3:","Value 4:","Value 5:"]},{"name":"My Vision Board Categories","description":"Draw, paste, or write your vision for each area","items":["Career & Purpose: [space for images/words]","Health & Body: [space for images/words]","Relationships & Love: [space for images/words]","Adventure & Travel: [space for images/words]","Home & Environment: [space for images/words]","Personal Growth: [space for images/words]","Fun & Joy: [space for images/words]"]},{"name":"My Affirmations","description":"Write 5 I AM statements about your future self","items":["I am:","I am:","I am:","I am:","I am:"]}],"affirmation":"Vision boards work because clarity creates motivation. When you know where you are going, every decision becomes easier."}`,
    },
    techie: {
      'sprint-planner': `Create a 2-week sprint planning template for software teams. Return ONLY valid JSON:\n{"title":"Sprint Planner","subtitle":"Plan, commit, ship — 2 weeks at a time","date_label":"Sprint dates:","top_3_priorities":["Sprint Goal #1","Sprint Goal #2","Sprint Goal #3"],"categories":[{"name":"Sprint Backlog — Committed Items","icon":"📋","lines":8},{"name":"Story Points Total","icon":"📊","lines":2},{"name":"In Progress","icon":"🔄","lines":5},{"name":"Blockers & Dependencies","icon":"🚧","lines":4},{"name":"Done ✓","icon":"✅","lines":6},{"name":"Team Capacity Notes","icon":"👥","lines":3}],"affirmation":"A sprint is a promise to your team. Make it realistic, then make it happen."}`,
      'code-review': `Create a comprehensive code review checklist. Return ONLY valid JSON:\n{"title":"Code Review Checklist","subtitle":"Systematic review leads to better code and better teams","sections":[{"name":"🔍 Functionality","description":"Does it work correctly?","items":["Logic is correct and handles the expected use cases","Edge cases are identified and handled","Error handling is present and meaningful","Unit tests cover the new code","Integration or E2E tests updated if needed","No obvious bugs or unintended side effects"]},{"name":"📖 Readability & Maintainability","description":"Will the next developer understand this?","items":["Variable and function names are clear and descriptive","Functions do one thing and do it well","Comments explain WHY not WHAT","No commented-out dead code","Code follows existing style and conventions","Complex logic is extracted into named functions"]},{"name":"🔒 Security","description":"Is this code safe?","items":["No hardcoded secrets, API keys, or credentials","User input is validated and sanitized","Authentication and authorization checks in place","SQL / NoSQL injection risks addressed","Sensitive data is not logged","Dependencies do not introduce known CVEs"]},{"name":"⚡ Performance","description":"Will this scale?","items":["No N+1 query problems","Database queries are indexed appropriately","Expensive operations are not in loops","Caching considered for repeated reads","Memory leaks not introduced","API calls are not made unnecessarily"]},{"name":"🏗️ Architecture","description":"Does this fit the bigger picture?","items":["Follows established patterns in the codebase","Does not introduce unnecessary coupling","Is it testable? Can this be mocked/stubbed?","Is there a simpler approach?","Does this create technical debt?"]}}],"reminder":"The goal of code review is shared understanding, not just finding bugs. Be kind, be clear, be constructive."}`,
      'side-project-tracker': `Create a side project tracker for developers. Return ONLY valid JSON:\n{"title":"Side Project Tracker","subtitle":"Your ideas deserve to become real","sections":[{"name":"Project #1","description":"Track your main side project","items":["Project name:","What it does:","Tech stack:","Status: [ ] Idea  [ ] In Progress  [ ] Launched  [ ] Paused","This week's goal:","Blockers:","Next milestone:"]},{"name":"Project #2","description":"Secondary project","items":["Project name:","What it does:","Status: [ ] Idea  [ ] In Progress  [ ] Launched  [ ] Paused","Next step:"]},{"name":"Project Ideas Backlog","description":"Ideas you want to build someday","items":["Idea 1:","Idea 2:","Idea 3:","Idea 4:","Idea 5:"]},{"name":"Weekly Side Project Log","description":"What did you ship or build this week?","items":["Monday:","Wednesday:","Friday / Weekend:","Shipped / deployed:","What I learned:"]}],"affirmation":"Side projects are how the best tools, companies, and careers begin. Keep building."}`,
      'learning-roadmap': `Create a tech skills learning roadmap planner. Return ONLY valid JSON:\n{"title":"Learning Roadmap","subtitle":"Build expertise one skill at a time","sections":[{"name":"Where I Am Now","description":"Honest assessment of your current skills","items":["Strong skills (I can teach these):","Solid skills (comfortable with these):","Weak spots (need improvement):","Completely new areas I want to explore:"]},{"name":"90-Day Learning Goal","description":"What do you want to learn in the next 3 months?","items":["Primary skill to learn:","Why this skill (career, project, curiosity):","How I will learn it (course, book, project, mentor):","Success criteria — how will I know I've learned it?","Time I can dedicate per week:"]},{"name":"Monthly Milestones","description":"Break the learning into monthly checkpoints","items":["Month 1 goal:","Month 2 goal:","Month 3 goal:"]},{"name":"Resources & References","description":"Curate your learning resources","items":["Book / Course:","YouTube channel / podcast:","Documentation / official guide:","Project I will build to practice:","Person or community to learn with:"]},{"name":"Notes & Key Learnings","description":"Capture insights as you learn","items":["Key insight 1:","Key insight 2:","Key insight 3:","Links and references:"]}],"affirmation":"The best developers are the ones who never stop being students."}`,
      'bug-triage': `Create a bug triage and investigation template. Return ONLY valid JSON:\n{"title":"Bug Triage Sheet","subtitle":"Systematic investigation leads to faster resolution","date_label":"Date reported:","categories":[{"name":"Bug Summary","icon":"🐛","lines":2},{"name":"Steps to Reproduce","icon":"🔁","lines":5},{"name":"Expected Behavior","icon":"✅","lines":2},{"name":"Actual Behavior","icon":"❌","lines":2},{"name":"Environment (OS, browser, version)","icon":"🖥️","lines":2},{"name":"Severity: [ ] Critical  [ ] High  [ ] Medium  [ ] Low","icon":"⚠️","lines":1},{"name":"Root Cause Investigation","icon":"🔍","lines":4},{"name":"Fix Implemented","icon":"🔧","lines":3},{"name":"Tests Added","icon":"🧪","lines":2},{"name":"Verified Fixed By","icon":"✓","lines":1}],"affirmation":"A well-documented bug is 50% fixed. Take time to understand before you fix."}`,
      'standup-notes': `Create a daily standup notes template. Return ONLY valid JSON:\n{"title":"Daily Standup Notes","subtitle":"Keep it under 15 minutes — update, don't discuss","date_label":"Date:","sections":[{"name":"Yesterday I Completed","description":"What did you actually finish?","items":["Task 1:","Task 2:","Task 3:","PR merged / deployed:"]},{"name":"Today I Am Working On","description":"What is on your plate today?","items":["Main focus:","Secondary task:","Meeting or review:","Expected completion:"]},{"name":"Blockers & Help Needed","description":"What is slowing you down?","items":["Blocker:","Who can unblock me:","How long I have been blocked:"]},{"name":"Notes & Follow-Ups","description":"Things to track outside standup","items":["Follow up with:","Decision needed from:","Async discussion needed on:","Technical debt to note:"]}],"affirmation":"Good standups create team alignment. Say what you did, say what you will do, say what is in your way."}`,
      'retro-template': `Create a sprint retrospective worksheet. Return ONLY valid JSON:\n{"title":"Sprint Retrospective","subtitle":"Reflect, learn, improve — continuously","date_label":"Sprint:","sections":[{"name":"What Went Well 🟢","description":"Celebrate the wins — team and individual","items":["Win 1:","Win 2:","Win 3:","Win 4:"]},{"name":"What Could Be Better 🟡","description":"Honest reflection — no blame, just observations","items":["Opportunity 1:","Opportunity 2:","Opportunity 3:"]},{"name":"What Went Poorly 🔴","description":"Be direct — what actually caused problems?","items":["Problem 1:","Root cause:","Problem 2:","Root cause:"]},{"name":"Action Items for Next Sprint","description":"Specific, owned, and actionable improvements","items":["Action 1 — Owner: _____ By when: _____","Action 2 — Owner: _____ By when: _____","Action 3 — Owner: _____ By when: _____"]},{"name":"Team Health Check","description":"Rate 1-10 and discuss briefly","items":["Team morale this sprint (1-10):","Communication quality (1-10):","Technical quality of work (1-10):","Process efficiency (1-10):"]}],"affirmation":"Teams that reflect and adapt outperform teams that just execute. Retrospectives are a competitive advantage."}`,
      'system-design': `Create a system design and architecture decision template. Return ONLY valid JSON:\n{"title":"System Design Notes","subtitle":"Think before you build — architecture decisions are hard to undo","date_label":"Date:","sections":[{"name":"Problem Statement","description":"What are we building and why?","items":["What problem does this solve?","Who are the users and what is the expected scale?","What are the performance requirements?","What are the availability requirements (SLA)?"]},{"name":"Requirements","description":"Functional and non-functional","items":["Functional requirements (what it must do):","Non-functional requirements (performance, security, scale):","Out of scope (explicitly excluded):","Assumptions being made:"]},{"name":"High-Level Design","description":"The big picture architecture","items":["System components (describe each):","Data flow (how data moves through the system):","Key APIs or interfaces:","Data storage strategy:"]},{"name":"Deep Dive — Critical Components","description":"Focus on the hardest parts","items":["Most complex component and approach:","Bottlenecks identified:","Caching strategy:","Database design:"]},{"name":"Trade-offs & Alternatives","description":"Show you considered options","items":["Approach chosen and why:","Alternative 1 (rejected because):","Alternative 2 (rejected because):","Technical debt acknowledged:"]},{"name":"Open Questions","description":"Things still to resolve","items":["Question 1:","Question 2:","Question 3:"]}],"affirmation":"Good system design is not about being clever — it's about being clear on trade-offs."}`,
    },
  };

  const nicheSpecific = specific[nicheId];
  if (nicheSpecific && nicheSpecific[productTypeId]) {
    return nicheSpecific[productTypeId];
  }

  return `Create content for a "${title}" printable worksheet for the "${nicheId}" niche.
Return ONLY valid JSON with: title, subtitle, and relevant sections array.
Each section should have: name, description, and items (array of strings).
Include an affirmation message at the end.
Make it practical, evidence-based, compassionate, and actionable. No markdown, just raw JSON.`;
}

// SEO keyword banks per niche for stronger Etsy search ranking
const NICHE_SEO_KEYWORDS: Record<string, string> = {
  adhd: 'ADHD planner, ADHD printable, executive function, neurodivergent planner, ADHD tools, focus planner, dopamine, time management ADHD',
  mdd: 'mental health journal, depression journal, mood tracker printable, self care planner, therapy worksheet, mental wellness, gratitude journal',
  anxiety: 'anxiety relief printable, CBT worksheet, mental health printable, grounding exercise, anxiety journal, calm down kit, therapy tools',
  social: 'social skills printable, conversation cards, social anxiety tools, boundary setting, communication printable, social script',
  human: 'printable planner, productivity planner, life planner, goal setting worksheet, habit tracker, organization printable, daily planner',
  techie: 'developer planner, software engineer printable, agile sprint planner, code review checklist, programmer gift, tech productivity',
};

export function getEtsyListingPrompt(nicheId: string, productTypeId: string, productName: string): string {
  const nicheKeywords = NICHE_SEO_KEYWORDS[nicheId] || 'printable, digital download, worksheet';

  return `Create a highly SEO-optimized Etsy listing for a printable digital download product.

Product: ${productName}
Niche: ${nicheId}
Type: ${productTypeId}
High-value niche keywords to incorporate: ${nicheKeywords}

SEO rules:
- Title: exactly under 140 chars, front-load the most searched keywords, include "printable" and "digital download", natural language
- Tags: EXACTLY 13 tags, each tag under 20 characters, use high-search-volume Etsy keywords, mix broad (e.g. "printable planner") and specific (e.g. "ADHD daily planner") terms
- Description: 200-350 words. Opening sentence hooks with main keyword. Explain what it is, who it is for, exactly what is included, how to use it. Mention: instant digital download, PDF format, US Letter + A4 sizes included, print at home or at a print shop. Use natural keyword placement. End with a warm call to action.
- Category: return a category_path and taxonomy_id suitable for Etsy digital printables.

Return ONLY valid JSON (no markdown, no code blocks):
{
  "title": "...",
  "tags": ["tag1", "tag2", "tag3", "tag4", "tag5", "tag6", "tag7", "tag8", "tag9", "tag10", "tag11", "tag12", "tag13"],
  "description": "...",
  "category_path": "Paper & Party Supplies > Paper > Calendars & Planners",
  "taxonomy_id": 2078
}`;
}
